import { Box, Container, Spacer, VStack ,Checkbox, Input } from "@chakra-ui/react"
import { useState } from "react"

export const IncompleteTodos = (props) => {
    const { incompleteTodos, onClickComplete, onClickDelete } = props;

    const [isClick, setIsClick] = useState(false);

    const handleClick = (index) => {
      // 真偽値をfalseからtrueに変更
      setIsClick(true);
      console.log(isClick);
      // 未完了タスクをコピー
      // 編集対象のタスクを取得
      // タスクを編集するためのインプットを表示 
    }

    return (
    <div>
            <VStack>
            <Container maxW='xl' bg='blue.600' color='white'>
        <p>未完了のToDo</p>
        <ul>
          {incompleteTodos.map((todo, index) => (
          <li key={todo}>
            <Box display="flex" p={2}>
            <Checkbox onChange={() => onClickComplete(index)}></Checkbox>
            <p>{todo}</p>
            <Spacer />
            <Box px={2}>



              <div>
                {isClick ? (<form><input type="text" /></form>) : <div>Today</div>}
                <button onClick={handleClick}>Edit</button>
              </div>


            </Box>
            <button onClick={() => onClickDelete(index)}>削除</button>

            </Box>
          </li>
            )
        )}
        </ul>
        </Container>
        </VStack>
    </div>
    )
}
